const items = $input.all();
const processedItems = [];

for (const item of items) {
  // Récupération de la propriété "*Référence n8n*"
  const textData = item.json["*Référence n8n*"] || '';

  // Initialisation des variables
  let parsedData = {
    nom_tache: '',
    id_database: '',
    id_page: '',
    id_fournisseur: '',
    ticket: null
  };

  if (textData) {
    // Normalisation : Remplacer les \n littéraux par de vrais sauts de ligne
    const normalizedText = textData.replace(/\\n/g, '\n');

    // Découpage du texte par lignes (après normalisation)
    const lignes = normalizedText.split('\n');

    // [1] Nom de la tâche (première ligne)
    if (lignes[0]) {
      parsedData.nom_tache = lignes[0].trim();
    }

    // Parsing des lignes suivantes
    for (let i = 1; i < lignes.length; i++) {
      const ligne = lignes[i].trim();

      // [2] ID Database
      if (ligne.startsWith('ID Database:')) {
        parsedData.id_database = ligne.replace('ID Database:', '').trim();
      }

      // [3] ID Page
      if (ligne.startsWith('ID Page:')) {
        parsedData.id_page = ligne.replace('ID Page:', '').trim();
      }

      // [4] ID Fournisseur (uniquement pour les certificats)
      if (ligne.startsWith('ID Fournisseur :')) {
        parsedData.id_fournisseur = ligne.replace('ID Fournisseur :', '').trim();
      }

      // [5] Ticket (extraction du numéro)
      if (ligne.startsWith('Ticket :') || ligne.startsWith('Ticket:')) {
        const ticketText = ligne.replace(/Ticket\s*:\s*/i, '').trim();
        const ticketNumber = parseInt(ticketText, 10);

        // Vérification que c'est bien un nombre valide
        if (!isNaN(ticketNumber)) {
          parsedData.ticket = ticketNumber;
        }
      }
    }
  }

  // Sortie simplifiée - seulement les 5 propriétés demandées
  processedItems.push({
    json: parsedData
  });
}

return processedItems;

// === Code Node n8n — Recalage sur jours ouvrés (UTC-safe) ===
const items = $input.all();
const out = [];

// Helpers UTC pour éviter les décalages DST/fuseau
const MS_PER_DAY = 24 * 60 * 60 * 1000;

function parseISODateOnly(s) {
  if (!s) return null;
  return new Date(`${s}T00:00:00Z`); // force minuit UTC
}

function toISODateOnly(dUtc) {
  return dUtc.toISOString().slice(0, 10);
}

function addDaysUTC(dUtc, n) {
  const d = new Date(Date.UTC(dUtc.getUTCFullYear(), dUtc.getUTCMonth(), dUtc.getUTCDate()));
  d.setUTCDate(d.getUTCDate() + n);
  return d;
}

// Si samedi/dimanche → avance jusqu'au lundi
function nextWorkingDayUTC(dUtc) {
  let res = new Date(Date.UTC(dUtc.getUTCFullYear(), dUtc.getUTCMonth(), dUtc.getUTCDate()));
  const dow = res.getUTCDay(); // 0=dim, 6=sam
  if (dow === 6) res = addDaysUTC(res, 2); // samedi -> lundi
  else if (dow === 0) res = addDaysUTC(res, 1); // dimanche -> lundi
  return res;
}

for (const item of items) {
  const data = item.json || {};
  const startProp = data["Date de début"]?.start;
  const endProp   = data["Date de fin"]?.start;
  const jours     = Number.isFinite(Number(data.jours)) ? Number(data.jours) : 0;

  // 1) GAP en jours calendaires (0 si info manquante)
  const startOrig = parseISODateOnly(startProp);
  const endOrig   = parseISODateOnly(endProp);
  let gap = 0;
  if (startOrig && endOrig) {
    gap = Math.round((endOrig - startOrig) / MS_PER_DAY);
  }

  // 2) Nouvelle Date de début = (Date de début + jours) puis ajustée jour ouvré
  //    Fallback: si start manquant, on part d'aujourd'hui.
  const todayStr  = new Date().toISOString().slice(0, 10);
  const baseStart = startOrig || parseISODateOnly(todayStr);
  const candidateStart = addDaysUTC(baseStart, jours);
  const startWorking   = nextWorkingDayUTC(candidateStart);
  const startOutStr    = toISODateOnly(startWorking);

  // 3) Nouvelle Date de fin = (nouvelle Date de début + gap) puis ajustée jour ouvré
  const candidateEnd = addDaysUTC(startWorking, gap);
  const endWorking   = nextWorkingDayUTC(candidateEnd);
  const endOutStr    = toISODateOnly(endWorking);

  // Logs utiles
  console.log("=== DATES ===", {
    jours,
    gap,
    start_input: startProp || "(null->today)",
    end_input: endProp || "(null)",
    start_out: startOutStr,
    end_out: endOutStr,
  });

  out.push({
    json: {
      ...data,
      "Date de début": { start: startOutStr, end: null, time_zone: null },
      "Date de fin":   { start: endOutStr,   end: null, time_zone: null },
    }
  });
}

return out;

