return items.map(i => {
  const startedAt = new Date().toISOString();
  i.json._log = {
    runId: startedAt,
    workflow: i.json._log?.workflow || null,
    executionId: i.json._log?.executionId || null,
    startedAt,
    ok: 0,
    ko: 0,
    actions: [],
    failedNodes: {}
  };
  return i;
});

return items.map(i => {
  const log = i.json._log || {};

  // LIGNE 5 CORRIGÉE
  const nodeName = i.json._lastNode || 'UnknownNode';

  const failed = !!i.json._hadError || !!i.json.error;

  // Message adaptatif
  const msg = i.json.error?.message || 
              i.json._errMsg || 
              (failed ? 'Erreur détectée' : 'Succès');

  (log.actions ||= []).push({ node: nodeName, ok: !failed, msg });

  if (failed) {
    log.ko = (log.ko || 0) + 1;
    log.failedNodes = log.failedNodes || {};
    log.failedNodes[nodeName] = true;
  } else {
    log.ok = (log.ok || 0) + 1;
  }

  i.json._log = log;
  return i;
});

const i = items[0];
const log = i.json._log || {};
log.finishedAt = new Date().toISOString();

const start = new Date(log.startedAt || log.runId || Date.now()).getTime();
const end = new Date(log.finishedAt).getTime();
log.durationSec = Math.round((end - start) / 1000);

// 🎯 CORRECTION : Extraire les noms de nœuds uniques des échecs
const failedNodeNames = [];
const uniqueErrorMessages = [];

// Parcourir les actions pour identifier les échecs
if (log.actions && Array.isArray(log.actions)) {
  log.actions.forEach(action => {
    if (!action.ok) {
      // Ajouter le nom du nœud s'il n'est pas déjà présent
      if (!failedNodeNames.includes(action.node)) {
        failedNodeNames.push(action.node);
      }

      // Ajouter le message d'erreur s'il n'est pas déjà présent
      if (action.msg && !uniqueErrorMessages.includes(action.msg)) {
        uniqueErrorMessages.push(action.msg);
      }
    }
  });
}

// 🎯 RÉSULTATS CORRIGÉS
log.failedNodesList = failedNodeNames; // Noms uniques des nœuds en échec
log.uniqueErrorMessages = uniqueErrorMessages; // Messages d'erreur uniques
log.errorSummary = uniqueErrorMessages.join(' | '); // Compilation des erreurs

// Stats améliorées
log.stats = {
  totalProcessed: log.ok + log.ko,
  successCount: log.ok,
  failureCount: log.ko,
  successRate: `${Math.round((log.ok / (log.ok + log.ko)) * 100)}%`,
  uniqueFailedNodes: failedNodeNames.length,
  distinctErrors: uniqueErrorMessages.length
};

i.json._log = log;
return [i];

