// Consolidation COMPLÈTE des logs
const logData = {
  workflow: $('Log Meta (expressions)').first().json._log?.workflow || "WorkFlow 01",
  executionId: $execution.id,
  startedAt: $('Start Log').first().json._log?.startedAt,
  finishedAt: new Date().toISOString(),
  runId: $('Start Log').first().json._log?.runId,

  // Consolidation des compteurs
  ok: $input.all().reduce((sum, item) => sum + (item.json._log?.ok || 0), 0),
  ko: $input.all().reduce((sum, item) => sum + (item.json._log?.ko || 0), 0),
  failedNodes: $input.all().flatMap(item => item.json._log?.failedNodes || []),

  // Logique Actions
  actions: (() => {
    const koCount = $input.all().reduce((sum, item) => sum + (item.json._log?.ko || 0), 0);
    if (koCount === 0) {
      return [{ msg: "Pass" }];
    } else {
      const allActions = $input.all().flatMap(item => item.json._log?.actions || []);
      return allActions.filter(action => action.msg !== "Pass");
    }
  })()
};

return [{ json: { _log: logData } }];

